# Final fix: update vite.config.ts + put auth in public/
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\FINALFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying final fix..." -ForegroundColor Cyan

# frontend/vite.config.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend/vite.config.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/vite.config.ts" -ForegroundColor Green

# frontend/public/dsm-auth.html
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend/public/dsm-auth.html"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/public/dsm-auth.html" -ForegroundColor Green

git add frontend/vite.config.ts frontend/public/dsm-auth.html
git commit -m "fix: remove dsm-auth.html from Vite entries, serve from public/ instead"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Done! After Netlify builds, try: https://dsm.4thandbailey.com/dsm-auth.html" -ForegroundColor Green
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}